import { type CSSProperties, SVGAttributes } from 'react';

type SVGTextProps = SVGAttributes<SVGTextElement>;

type OwnProps = {
  /** Rotational angle of the text. */
  angle?: number;
  /** Horizontal text anchor. */
  textAnchor?: 'start' | 'middle' | 'end' | 'inherit';
  /** Vertical text anchor. */
  verticalAnchor?: 'start' | 'middle' | 'end';
  /** x position of the text. */
  x?: string | number;
  /** y position of the text. */
  y?: string | number;
  /** dx offset of the text. */
  dx?: string | number;
  /** dy offset of the text. */
  dy?: string | number;
  /** Font size of text. */
  fontSize?: string | number;
  /** Font family of text. */
  fontFamily?: string;
  /** Fill color of text. */
  fill?: string;
  /** Maximum width to occupy (approximate as words are not split). */
  width?: number;
  /** Styles to be applied to the text (and used in computation of its size). */
  style?: CSSProperties;
  /** String (or number coercible to one) to be styled and positioned. */
  children?: string | number;
};

export type TextProps = OwnProps & Omit<SVGTextProps, keyof OwnProps>;

/**
 * Function that returns TextProps for a specific tick value
 * @typeparam Value - The tick value type
 */
export type TickLabelProps<Value> = (
  value: Value,
  index: number,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  values: any, // Using any to match visx's implementation which can pass different shapes of data
) => Partial<TextProps>;

// Memoization cache for getStringWidth
const stringWidthCache = new Map<string, number | null>();

/**
 * Get the computed width of a string.
 * Recreation from visx/text
 * to maintain consistent text truncation behavior.
 *
 * @param str - The string to measure
 * @param style - Optional style object to apply to the text element
 * @returns The computed width of the string or null if measurement fails
 */
export function getStringWidth(
  str: string,
  style?: CSSProperties,
): number | null {
  try {
    const cacheKey = `${str}_${JSON.stringify(style || {})}`;
    if (stringWidthCache.has(cacheKey)) {
      const cachedResult = stringWidthCache.get(cacheKey);
      return cachedResult !== undefined ? cachedResult : null;
    }

    const MEASUREMENT_ELEMENT_ID = '__react_svg_text_measurement_id';

    let textEl = document.getElementById(
      MEASUREMENT_ELEMENT_ID,
    ) as SVGTextElement | null;
    if (!textEl) {
      const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
      svg.setAttribute('aria-hidden', 'true');
      svg.style.width = '0';
      svg.style.height = '0';
      svg.style.position = 'absolute';
      svg.style.top = '-100%';
      svg.style.left = '-100%';
      textEl = document.createElementNS('http://www.w3.org/2000/svg', 'text');
      textEl.setAttribute('id', MEASUREMENT_ELEMENT_ID);
      svg.appendChild(textEl);
      document.body.appendChild(svg);
    }

    // Apply style and set text content
    Object.assign(textEl.style, style);
    textEl.textContent = str;

    // Get computed width
    const width = textEl.getComputedTextLength();

    // Cache the result
    stringWidthCache.set(cacheKey, width);

    return width;
  } catch {
    // Error is caught and ignored since we just want to return null on any failure
    return null;
  }
}
